package thanos

// CrossTrade L2 contract creation bytecodes.
// Extracted from crossTrade repo hardhat artifacts (L2toL2Implementation branch).
// Source: crossTrade/artifacts/{ContractName}.sol/{ContractName}.json "bytecode.object" field

import (
	"encoding/hex"
	"fmt"
	"strings"
)

var (
	// L2CrossTradeBytecode is the L2CrossTrade implementation creation bytecode
	L2CrossTradeBytecode = mustDecodeHex("")

	// L2CrossTradeProxyBytecode is the L2CrossTradeProxy creation bytecode
	L2CrossTradeProxyBytecode = mustDecodeHex("")

	// L2toL2CrossTradeL2Bytecode is the L2toL2CrossTradeL2 implementation creation bytecode
	L2toL2CrossTradeL2Bytecode = mustDecodeHex("")

	// L2toL2CrossTradeProxyBytecode is the L2toL2CrossTradeProxy creation bytecode
	L2toL2CrossTradeProxyBytecode = mustDecodeHex("")
)

func mustDecodeHex(hexStr string) []byte {
	b, err := hex.DecodeString(strings.TrimPrefix(hexStr, "0x"))
	if err != nil {
		panic(fmt.Sprintf("invalid bytecode hex: %v", err))
	}
	return b
}
